previewCss:
.darma-loader-darma-custom-316 {
  color: var(--loader-color, #2563eb);
  width: 54px;
  aspect-ratio: .5;
  display: grid;
}
.darma-loader-darma-custom-316:before {
  content: "";
  width: 30%;
  aspect-ratio: 1;
  border-radius: 50%;
  margin: auto auto 0;
  background: var(--loader-color, #2563eb);
  animation: darma-loader-darma-custom-316-l9-0 .5s cubic-bezier(0,800,1,800) infinite;
}
.darma-loader-darma-custom-316:after {
  content: "";
  width: 100%;
  aspect-ratio: 1/cos(30deg);
  margin: 0 auto auto;
  clip-path: polygon(50% -50%,100% 50%,50% 150%,0 50%);
  background: var(--loader-secondary-color, #38bdf8);
  animation: darma-loader-darma-custom-316-l9-1 .5s linear infinite;
}
@keyframes darma-loader-darma-custom-316-l9-0 {
  0%,2%  {translate: 0   0%}
  98%,to {translate: 0 -.2%}
}
@keyframes darma-loader-darma-custom-316-l9-1 {
  0%,5%  {rotate:  0deg}
  95%,to {rotate:-60deg}
}

